import React from 'react'
import CountUp from 'react-countup';
import LazyLoad from 'react-lazyload';
import './Facts.css'

function Facts() {
    return (
        <section id="facts" className="facts">
            <div className="container">
                <div className="section-title">
                    <h2>Facts</h2>
                    {/* <p>Magnam dolores commodi suscipit. Necessitatibus eius consequatur ex aliquid fuga eum quidem. Sit sint consectetur velit. Quisquam quos quisquam cupiditate. Et nemo qui impedit suscipit alias ea. Quia fugiat sit in iste officiis commodi quidem hic quas.</p> */}
                </div>
                <LazyLoad height={200}>
                <div className="row no-gutters">

                    <div className="col-lg-3 col-md-6 d-md-flex align-items-md-stretch" data-aos="fade-up">
                        <div className="count-box">
                            <i className="icofont-coffee-mug"></i>
                            <CountUp end={500} separator="," suffix="+"/>
                            <p><strong>Cups of coffee</strong></p>
                        </div>
                    </div>

                    <div className="col-lg-3 col-md-6 d-md-flex align-items-md-stretch" data-aos="fade-up" data-aos-delay="100">
                        <div className="count-box">
                            <i className="icofont-document-folder"></i>
                            <CountUp end={15} separator="," />
                            <p><strong>Projects</strong></p>
                        </div>
                    </div>

                    <div className="col-lg-3 col-md-6 d-md-flex align-items-md-stretch" data-aos="fade-up" data-aos-delay="200">
                        <div className="count-box">
                            <i className="icofont-simple-smile"></i>
                            <CountUp end={10} separator="," />
                            <p><strong>Happy Clients</strong></p>
                        </div>
                    </div>

                    <div className="col-lg-3 col-md-6 d-md-flex align-items-md-stretch" data-aos="fade-up" data-aos-delay="300">
                        <div className="count-box">
                            <i className="icofont-meeting-add"></i>
                            <CountUp end={400} separator="," suffix="+"/>
                            <p><strong>Team Meetings</strong></p>
                        </div>
                    </div>

                </div>
                </LazyLoad>
            </div>
        </section>
    )
}

export default Facts
