import React from 'react'
import Particles from 'react-particles-js'
import './Homepage.css'
import Typed from 'react-typed';
import { params } from './particleConfig'

function Homepage() {
    return (
        <div id="homepage" className="homepage d-flex flex-column justify-content-center align-items-center">
            <Particles
                className="particles"
                params={params}
            />
            <div className="name-details" data-aos="fade-in">
                <h1>Hemant Nigam</h1>
                <p>I'm <Typed
                    strings={['Frontend Developer', 'Software Engineer']}
                    typeSpeed={40}
                    loop
                /></p>
            </div>

        </div>
    )
}

export default Homepage
